#include <bits/stdc++.h>
using namespace std;
int n,m,dp[35][35];
int main(){
    scanf("%d%d",&n,&m);
    dp[1][0]=1;
    for(int j=1;j<=m;j++)
        for(int i=1;i<=n;i++)
            dp[i][j]=dp[i-1+(i==1)*n][j-1]+dp[(i%n)+1][j-1];
    printf("%d",dp[1][m]);
    return 0;
}
